from __future__ import annotations

from pathlib import Path


PACKAGE_ROOT = Path(__file__).resolve().parents[1]
TRAINER = PACKAGE_ROOT / "LLaMA-Factory" / "src" / "llamafactory" / "train" / "ppo" / "trainer_qr_s_g.py"


BRANCH = "\n        if os.environ.get(\"REMA_PLANTUML_PPO\", \"0\") == \"1\":\n            return self.plantuml_ppo_train(resume_from_checkpoint=resume_from_checkpoint)\n"

METHOD = "\n    def _plantuml_extract_block(self, text: str) -> str:\n        value = (text or \"\").strip()\n        lower = value.lower()\n        start = lower.find(\"@startuml\")\n        end = lower.find(\"@enduml\", start + 1) if start >= 0 else -1\n        if start >= 0 and end >= 0:\n            return value[start : end + len(\"@enduml\")].strip()\n        return value\n\n    def _plantuml_extract_sample_id(self, text: str) -> str:\n        match = re.search(r\"Sample ID:\\s*([A-Za-z0-9_\\-.]+)\", text or \"\")\n        return match.group(1).strip() if match else \"\"\n\n    def _plantuml_load_reward_map(self):\n        reward_map_path = os.environ.get(\"REMA_PLANTUML_REWARD_MAP\")\n        if not reward_map_path:\n            raise ValueError(\"Please set REMA_PLANTUML_REWARD_MAP for PlantUML PPO.\")\n        reward_map = {}\n        with open(reward_map_path, \"r\", encoding=\"utf-8\") as handle:\n            for line in handle:\n                if line.strip():\n                    item = json.loads(line)\n                    reward_map[item[\"id\"]] = item\n        if not reward_map:\n            raise ValueError(\"PlantUML reward map is empty: {}\".format(reward_map_path))\n        return reward_map\n\n    @torch.no_grad()\n    def _plantuml_get_inputs(self, batch: Dict[str, \"torch.Tensor\"]) -> Tuple[List[\"torch.Tensor\"], List[\"torch.Tensor\"]]:\n        target_device = self.accelerator.device if hasattr(self, \"accelerator\") else get_current_device()\n        generation_batch = {\n            \"input_ids\": batch[\"input_ids\"].to(target_device),\n            \"attention_mask\": batch[\"attention_mask\"].to(target_device),\n        }\n        max_new_tokens = int(os.environ.get(\"REMA_PLANTUML_MAX_NEW_TOKENS\", \"512\"))\n\n        with unwrap_model_for_generation(self.model, self.accelerator) as unwrapped_model:\n            unwrapped_model: \"AutoModelForCausalLMWithValueHead\" = self.accelerator.unwrap_model(self.model)\n            if self.model_args.upcast_layernorm:\n                layernorm_params = dump_layernorm(unwrapped_model)\n\n            generate_output: \"torch.Tensor\" = unwrapped_model.generate(\n                generation_config=self.generation_config,\n                logits_processor=get_logits_processor(),\n                max_new_tokens=max_new_tokens,\n                **generation_batch,\n            )\n\n            if self.model_args.upcast_layernorm:\n                restore_layernorm(unwrapped_model, layernorm_params)\n\n        query = generation_batch[\"input_ids\"].detach().cpu()\n        response = generate_output[:, generation_batch[\"input_ids\"].size(-1) :].detach().cpu()\n        queries, responses = [], []\n        for i in range(len(query)):\n            query_start_index = (query[i] != self.tokenizer.pad_token_id).nonzero()[0].item()\n            response_indexes = (response[i] != self.tokenizer.pad_token_id).nonzero()\n            if len(response_indexes) == 0:\n                response_length = 1\n            elif self.tokenizer.eos_token_id == self.tokenizer.pad_token_id:\n                response_length = response_indexes[-1].item() + 2\n            else:\n                response_length = response_indexes[-1].item() + 1\n            queries.append(query[i, query_start_index:])\n            responses.append(response[i, :response_length])\n        return queries, responses\n\n    def plantuml_ppo_train(self, resume_from_checkpoint: Optional[str] = None) -> None:\n        r\"\"\"\n        PlantUML PPO smoke loop.\n\n        This branch intentionally bypasses the original HotpotQA QR/Selector/Generator code path.\n        It optimizes the final PlantUML generator against a local rule reward map.\n        \"\"\"\n        if resume_from_checkpoint is not None:\n            raise ValueError(\"`resume_from_checkpoint` will be supported in the future version.\")\n\n        fusion_dir = os.environ.get(\"REMA_FUSION_DIR\")\n        if fusion_dir and fusion_dir not in sys.path:\n            sys.path.insert(0, fusion_dir)\n        from rema.plantuml_canonicalizer import canonicalize_plantuml\n        from rema.reward_rule import compute_rule_reward\n\n        reward_map = self._plantuml_load_reward_map()\n        trace_path = os.path.join(self.args.output_dir, \"plantuml_reward_trace.jsonl\")\n        os.makedirs(self.args.output_dir, exist_ok=True)\n\n        total_train_batch_size = (\n            self.args.per_device_train_batch_size\n            * self.args.gradient_accumulation_steps\n            * self.finetuning_args.ppo_buffer_size\n            * self.args.world_size\n        )\n        if self.args.max_steps > 0:\n            num_examples = total_train_batch_size * self.args.max_steps\n            num_train_epochs = sys.maxsize\n            max_steps = self.args.max_steps\n            steps_in_epoch = self.args.max_steps\n        else:\n            len_dataloader = len(self.dataloader)\n            num_examples = len(self.dataset)\n            num_train_epochs = self.args.num_train_epochs\n            max_steps = math.ceil(num_train_epochs * len_dataloader)\n            steps_in_epoch = len_dataloader\n\n        self.state.max_steps = max_steps\n        self.state.num_train_epochs = num_train_epochs\n        self.state.is_local_process_zero = self.is_local_process_zero()\n        self.state.is_world_process_zero = self.is_world_process_zero()\n\n        if self.is_world_process_zero():\n            logger.info(\"***** Running PlantUML PPO-v0 training *****\")\n            logger.info(\"  Num examples = {:,}\".format(num_examples))\n            logger.info(\"  Total training steps = {:,}\".format(max_steps))\n            logger.info(\"  Number of trainable parameters = {:,}\".format(count_parameters(self.model)[0]))\n\n        dataiter = iter(self.dataloader)\n        loss_meter = AverageMeter()\n        reward_meter = AverageMeter()\n        self.callback_handler.on_train_begin(self.args, self.state, self.control)\n\n        reward_mode = os.environ.get(\"REMA_PLANTUML_REWARD_MODE\", \"relation_focus\")\n\n        for step in tqdm(range(max_steps), disable=not self.is_local_process_zero()):\n            try:\n                batch = next(dataiter)\n            except StopIteration:\n                dataiter = iter(self.dataloader)\n                batch = next(dataiter)\n\n            self.model.eval()\n            self.tokenizer.padding_side = \"right\"\n            generation_batch = {\n                \"input_ids\": batch[\"input_ids\"],\n                \"attention_mask\": batch[\"attention_mask\"],\n            }\n            queries, responses = self._plantuml_get_inputs(generation_batch)\n\n            rewards = []\n            trace_items = []\n            decoded_prompts = self.tokenizer.batch_decode(generation_batch[\"input_ids\"], skip_special_tokens=True)\n            decoded_outputs = self.tokenizer.batch_decode(responses, skip_special_tokens=True)\n            for prompt_text, output_text in zip(decoded_prompts, decoded_outputs):\n                sample_id = self._plantuml_extract_sample_id(prompt_text)\n                gold = reward_map.get(sample_id, {}).get(\"gold_plantuml\", \"\")\n                prediction = self._plantuml_extract_block(output_text)\n                strict = compute_rule_reward(prediction=prediction, reference=gold).to_dict()\n                normalized_prediction = canonicalize_plantuml(prediction)\n                normalized_gold = canonicalize_plantuml(gold)\n                normalized = compute_rule_reward(\n                    prediction=normalized_prediction,\n                    reference=normalized_gold,\n                ).to_dict()\n\n                if reward_mode == \"relation_focus\":\n                    score = (\n                        0.65 * float(normalized[\"total\"])\n                        + 0.20 * float(normalized[\"relation_pair_f1\"])\n                        + 0.10 * float(normalized[\"multiplicity_f1\"])\n                        + 0.05 * float(normalized[\"relation_label_f1\"])\n                    )\n                else:\n                    score = float(normalized[\"total\"])\n\n                if float(normalized[\"format_score\"]) < 1.0 or float(normalized[\"syntax_score\"]) < 1.0:\n                    score -= 0.20\n                score = max(0.0, min(1.0, score))\n                rewards.append(torch.tensor(score))\n                trace_items.append(\n                    {\n                        \"step\": step,\n                        \"id\": sample_id,\n                        \"reward\": round(score, 6),\n                        \"strict\": strict,\n                        \"normalized\": normalized,\n                        \"prediction\": prediction,\n                    }\n                )\n\n            with open(trace_path, \"a\", encoding=\"utf-8\") as handle:\n                for item in trace_items:\n                    handle.write(json.dumps(item, ensure_ascii=False) + \"\\n\")\n\n            self.model.train()\n            stats = self.step(queries, responses, rewards)\n            self.tokenizer.padding_side = \"left\"\n            loss_meter.update(float(stats[\"ppo/loss/total\"]), n=len(rewards))\n            reward_meter.update(torch.stack(rewards).mean().item(), n=len(rewards))\n\n            if self.is_local_process_zero() and (step + 1) % self.args.logging_steps == 0:\n                logs = dict(\n                    loss=round(loss_meter.avg, 4),\n                    reward=round(reward_meter.avg, 4),\n                    learning_rate=stats[\"ppo/learning_rate\"],\n                    epoch=round(step / steps_in_epoch, 2),\n                )\n                tqdm.write(str(logs))\n                logs[\"step\"] = step\n                self.state.log_history.append(logs)\n                self.callback_handler.on_log(self.args, self.state, self.control, logs)\n                loss_meter.reset()\n                reward_meter.reset()\n\n            if (step + 1) % self.args.save_steps == 0:\n                self.save_model(os.path.join(self.args.output_dir, \"{}-{}\".format(PREFIX_CHECKPOINT_DIR, self.state.global_step + 1)))\n                self.callback_handler.on_save(self.args, self.state, self.control)\n\n            self.state.global_step += 1\n            self.callback_handler.on_step_end(self.args, self.state, self.control)\n            if self.control.should_epoch_stop or self.control.should_training_stop:\n                break\n\n        self.callback_handler.on_train_end(self.args, self.state, self.control)\n\n"


def main() -> None:
    if not TRAINER.exists():
        raise SystemExit(f"Trainer not found: {TRAINER}")
    text = TRAINER.read_text(encoding="utf-8")
    if "def plantuml_ppo_train" in text:
        print("PlantUML PPO-v0 patch already applied.")
        return

    needle = '        if resume_from_checkpoint is not None:\n            raise ValueError("`resume_from_checkpoint` will be supported in the future version.")\n'
    if needle not in text:
        raise SystemExit("Could not find ppo_train resume guard for branch insertion.")
    text = text.replace(needle, needle + BRANCH, 1)

    method_anchor = "    @override\n    def create_optimizer"
    if method_anchor not in text:
        raise SystemExit("Could not find create_optimizer anchor for method insertion.")
    text = text.replace(method_anchor, METHOD + "\n" + method_anchor, 1)
    TRAINER.write_text(text, encoding="utf-8")
    print(f"Applied PlantUML PPO-v0 patch: {TRAINER}")


if __name__ == "__main__":
    main()
